import { Component, h, Prop } from '@stencil/core';
import { twMerge } from 'tailwind-merge';

@Component({
  tag: 'wdpr-week-header',
  shadow: true,
})
export class WdprWeekHeader {
  @Prop() fullWidth: boolean = false;

  private getLocalizedWeekdays(): string[] {
    const formatter = new Intl.DateTimeFormat(navigator.language || 'default', { weekday: 'long' });
    const weekdays = [];

    const referenceDate = new Date(2025, 8, 14); // Reference date set to Sunday
    for (let day = 0; day < 7; day++) {
      const date = new Date(referenceDate);
      date.setDate(referenceDate.getDate() + day);
      weekdays.push(formatter.format(date));
    }

    return weekdays;
  }

  private get _wrapperClasses(): string {
    const width = this.fullWidth ? 'w-full' : 'max-w-xs';

    return twMerge('flex flex-row label-medium !text-text-disclaimer', width);
  }

  render() {
    const localizedWeekdays = this.getLocalizedWeekdays();

    return (
      <div class={this._wrapperClasses} part="week-header-wrapper" role="row">
        {localizedWeekdays.map(day => (
          <span class="flex-1 py-050 text-center" part="week-header-label" role="columnheader">
            <span class="sr-only">{day}</span>
            <span aria-hidden="true">{day[0]}</span>
          </span>
        ))}
      </div>
    );
  }
}
